def run_command(
    cmd: List[str],
    capture_output: bool = True,
    check: bool = True,
    cwd: Optional[Path] = None,
) -> subprocess.CompletedProcess:
    """Run a subprocess command with logging."""
    logger.debug("Running: %s", " ".join(cmd))
    try:
        result = subprocess.run(
            cmd,
            capture_output=capture_output,
            text=True,
            check=check,
            cwd=cwd or PROJECT_ROOT,
        )
        return result
    except subprocess.CalledProcessError as exc:
        logger.error("Command failed: %s", " ".join(cmd))
        if exc.stderr:
            logger.error("stderr: %s", exc.stderr.strip())
        raise
    except FileNotFoundError:
        logger.error("Command not found: %s", cmd[0])
        logger.error(
            "Please install the required tool. "
            "See the setup instructions in this script's docstring."
        )
        raise SystemExit(1)


def compute_file_hash(filepath: Path, algorithm: str = "sha256") -> str:
    """Compute the hash of a file."""
    h = hashlib.new(algorithm)
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            h.update(chunk)
    return f"{algorithm}:{h.hexdigest()}"


def is_tool_available(tool_name: str) -> bool:
    """Check if a CLI tool is available on PATH."""
    try:
        subprocess.run(
            [tool_name, "--version"],
            capture_output=True,
            check=True,
        )
        return True
    except (subprocess.CalledProcessError, FileNotFoundError):
        return False


def load_config() -> ProjectConfig:
    """Load project configuration from .depmanager.json."""
    config_path = PROJECT_ROOT / CONFIG_FILENAME
    if config_path.exists():
        with open(config_path) as f:
            data = json.load(f)
        backend = Backend(data.get("backend", "pip-tools"))
        return ProjectConfig(
            backend=backend,
            hash_algorithm=data.get("hash_algorithm", "sha256"),
            auto_audit=data.get("auto_audit", True),
            python_version=data.get("python_version", ""),
            project_name=data.get("project_name", ""),
            environments=data.get("environments", ["prod", "dev", "ci"]),
            lock_file_version=data.get("lock_file_version", 1),
            pypi_index_url=data.get("pypi_index_url", "https://pypi.org/simple"),
            extra_index_urls=data.get("extra_index_urls", []),
            trusted_hosts=data.get("trusted_hosts", []),
        )
    return ProjectConfig()


def save_config(config: ProjectConfig) -> None:
    """Save project configuration to .depmanager.json."""
    config_path = PROJECT_ROOT / CONFIG_FILENAME
    data = {
        "backend": config.backend.value,
        "hash_algorithm": config.hash_algorithm,
        "auto_audit": config.auto_audit,
        "python_version": config.python_version,
        "project_name": config.project_name,
        "environments": config.environments,
        "lock_file_version": config.lock_file_version,
        "pypi_index_url": config.pypi_index_url,
        "extra_index_urls": config.extra_index_urls,
        "trusted_hosts": config.trusted_hosts,
    }
    with open(config_path, "w") as f:
        json.dump(data, f, indent=2)
        f.write("\n")
    logger.info("Configuration saved to %s", config_path)


