# Backend: pip-tools (pip-compile / pip-sync)
# ---------------------------------------------------------------------------

class PipToolsBackend:
    """
    Manages dependencies using pip-tools (pip-compile & pip-sync).

    File layout:
        requirements.in          — top-level production dependencies
        requirements-dev.in      — top-level dev dependencies (includes -r requirements.in)
        requirements.txt         — locked production dependencies with hashes
        requirements-dev.txt     — locked dev dependencies with hashes
    """

    def __init__(self, config: ProjectConfig):
        self.config = config

    # -- Initialization -----------------------------------------------------

    def init(self) -> None:
        """Create initial requirements.in and requirements-dev.in files."""
        req_in = PROJECT_ROOT / "requirements.in"
        req_dev_in = PROJECT_ROOT / "requirements-dev.in"

        if not req_in.exists():
            req_in.write_text(REQUIREMENTS_IN_TEMPLATE)
            logger.info("Created %s", req_in)
        else:
            logger.info("%s already exists, skipping.", req_in)

        if not req_dev_in.exists():
            req_dev_in.write_text(REQUIREMENTS_DEV_IN_TEMPLATE)
            logger.info("Created %s", req_dev_in)
        else:
            logger.info("%s already exists, skipping.", req_dev_in)

        # Ensure pip-tools is installed
        if not is_tool_available("pip-compile"):
            logger.warning(
                "pip-tools is not installed. Installing now..."
            )
            run_command([sys.executable, "-m", "pip", "install", "pip-tools"])

        logger.info(
            "\n"
            "=== pip-tools Setup Complete ===\n"
            "\n"
            "Next steps:\n"
            "  1. Add your top-level dependencies to requirements.in\n"
            "  2. Add dev dependencies to requirements-dev.in\n"
            "  3. Run: python dependency_manager.py lock\n"
            "  4. Run: python dependency_manager.py sync --env dev\n"
            "\n"
            "The lock command generates requirements.txt and requirements-dev.txt\n"
            "with pinned versions and integrity hashes.\n"
            "\n"
            "IMPORTANT: Commit requirements.in, requirements-dev.in,\n"
            "           requirements.txt, and requirements-dev.txt to version control.\n"
        )

    # -- Locking ------------------------------------------------------------

    def lock(self) -> None:
        """
        Compile lock files from .in files.

        Generates:
            requirements.txt      — from requirements.in
            requirements-dev.txt  — from requirements-dev.in

        Both files include pinned versions and sha256 hashes.
        """
        self._ensure_input_files_exist()

        logger.info("Compiling requirements.txt from requirements.in ...")
        self._pip_compile("requirements.in", "requirements.txt")

        dev_in = PROJECT_ROOT / "requirements-dev.in"
        if dev_in.exists():
            logger.info("Compiling requirements-dev.txt from requirements-dev.in ...")
            self._pip_compile("requirements-dev.in", "requirements-dev.txt")

        logger.info("Lock files generated successfully.")
        self._print_lock_summary()

    def _pip_compile(self, input_file: str, output_file: str) -> None:
        """Run pip-compile with hashes and annotations."""
        cmd = [
            sys.executable, "-m", "piptools", "compile",
            "--generate-hashes",
            "--allow-unsafe",  # Pin setuptools, pip, etc.
            "--annotate",  # Add comments showing which package required each dep
            "--strip-extras",
            "--output-file", output_file,
            input_file,
        ]

        # Add index URL if custom
        if self.config.pypi_index_url != "https://pypi.org/simple":
            cmd.extend(["--index-url", self.config.pypi_index_url])

        for extra_url in self.config.extra_index_urls:
            cmd.extend(["--extra-index-url", extra_url])

        for host in self.config.trusted_hosts:
            cmd.extend(["--trusted-host", host])

        run_command(cmd)

    def _ensure_input_files_exist(self) -> None:
        req_in = PROJECT_ROOT / "requirements.in"
        if not req_in.exists():
            logger.error(
                "requirements.in not found. Run 'python dependency_manager.py init' first."
            )
            raise SystemExit(1)

    def _print_lock_summary(self) -> None:
        """Print a summary of the generated lock files."""
        for filename in ["requirements.txt", "requirements-dev.txt"]:
            filepath = PROJECT_ROOT / filename
            if filepath.exists():
                deps = self._count_dependencies(filepath)
                file_hash = compute_file_hash(filepath)
                logger.info(
                    "  %s: %d dependencies (hash: %s)",
                    filename,
                    deps,
                    file_hash,
                )

    @staticmethod
    def _count_dependencies(filepath: Path) -> int:
        """Count non-comment, non-empty lines that look like dependencies."""
        count = 0
        with open(filepath) as f:
            for line in f:
                stripped = line.strip()
                if stripped and not stripped.startswith("#") and not stripped.startswith("-"):
                    if "==" in stripped:
                        count += 1
        return count

    # -- Syncing ------------------------------------------------------------

    def sync(self, env: str = "dev") -> None:
        """
        Synchronize the current virtual environment with the lock file.

        This installs exactly the packages in the lock file and removes
        any packages not listed — ensuring a reproducible environment.

        Args:
            env: "prod" to install only requirements.txt,
                 "dev" to install requirements-dev.txt (which includes prod deps),
                 "ci" same as dev but with --pip-args='--no-cache-dir'.
        """
        self._ensure_venv()

        if env == "prod":
            lock_file = "requirements.txt"
        else:
            lock_file = "requirements-dev.txt"
            if not (PROJECT_ROOT / lock_file).exists():
                lock_file = "requirements.txt"
                logger.warning(
                    "requirements-dev.txt not found, falling back to requirements.txt"
                )

        if not (PROJECT_ROOT / lock_file).exists():
            logger.error(
                "%s not found. Run 'python dependency_manager.py lock' first.", lock_file
            )
            raise SystemExit(1)

        logger.info("Syncing environment (%s) with %s ...", env, lock_file)

        cmd = [sys.executable, "-m", "piptools", "sync", lock_file]
        if env == "ci":
            cmd.extend(["--pip-args", "--no-cache-dir"])

        run_command(cmd)
        logger.info("Environment synced successfully.")

    @staticmethod
    def _ensure_venv() -> None:
        """Warn if not running inside a virtual environment."""
        if not (
            hasattr(sys, "real_prefix")
            or (hasattr(sys, "base_prefix") and sys.base_prefix != sys.prefix)
        ):
            logger.warning(
                "You are NOT inside a virtual environment. "
                "It is strongly recommended to use a venv to avoid "
                "polluting the system Python installation.\n"
                "Create one with: python -m venv .venv && source .venv/bin/activate"
            )

    # -- Updating -----------------------------------------------------------

    def update(self, package: Optional[str] = None) -> None:
        """
        Update one or all packages to their latest allowed versions.

        Args:
            package: If provided, update only this package. Otherwise update all.
        """
        self._ensure_input_files_exist()

        if package:
            logger.info("Updating %s ...", package)
            upgrade_flag = ["--upgrade-package", package]
        else:
            logger.info("Updating all dependencies ...")
            upgrade_flag = ["--upgrade"]

        # Recompile with upgrade
        cmd = [
            sys.executable, "-m", "piptools", "compile",
            "--generate-hashes",
            "--allow-unsafe",
            "--annotate",
            "--strip-extras",
            "--output-file", "requirements.txt",
            *upgrade_flag,
            "requirements.in",
        ]
        run_command(cmd)

        dev_in = PROJECT_ROOT / "requirements-dev.in"
        if dev_in.exists():
            cmd_dev = [
                sys.executable, "-m", "piptools", "compile",
                "--generate-hashes",
                "--allow-unsafe",
                "--annotate",
                "--strip-extras",
                "--output-file", "requirements-dev.txt",
                *upgrade_flag,
                "requirements-dev.in",
            ]
            run_command(cmd_dev)

        logger.info("Update complete. Review changes with: git diff requirements*.txt")

    # -- Parsing lock files ------------------------------------------------

    def parse_lock_file(self, env: str = "prod") -> List[DependencyInfo]:
        """Parse a requirements.txt lock file into DependencyInfo objects."""
        filename = "requirements.txt" if env == "prod" else "requirements-dev.txt"
        filepath = PROJECT_ROOT / filename
        if not filepath.exists():
            return []

        dependencies = []
        current_dep: Optional[DependencyInfo] = None

        with open(filepath) as f:
            for line in f:
                stripped = line.strip()

                # Skip comments and blank lines (but parse annotations)
                if not stripped or stripped.startswith("#"):
                    continue

                # Skip options lines
                if stripped.startswith("-"):
                    continue

                # Hash line
                if stripped.startswith("--hash="):
                    if current_dep:
                        current_dep.hashes.append(stripped.replace("--hash=", ""))
                    continue

                # Dependency line: package==version
                match = re.match(
                    r"^([a-zA-Z0-9_.-]+)\[?([a-zA-Z0-9_,.-]*)\]?==([^\s;\\]+)"
                    r"(?:\s*;(.+?))?",
                    stripped.rstrip("\\").strip(),
                )
                if match:
                    if current_dep:
                        dependencies.append(current_dep)
                    extras = [e.strip() for e in match.group(2).split(",") if e.strip()]
                    markers = match.group(4).strip() if match.group(4) else None
                    current_dep = DependencyInfo(
                        name=match.group(1),
                        version=match.group(3),
                        extras=extras,
                        markers=markers,
                    )

            if current_dep:
                dependencies.append(current_dep)

        return dependencies


