class PoetryBackend:
    """
    Manages dependencies using Poetry.

    File layout:
        pyproject.toml  — project metadata and dependency specifications
        poetry.lock     — locked dependency tree with hashes
    """

    def __init__(self, config: ProjectConfig):
        self.config = config

    def init(self) -> None:
        """Initialize a new Poetry project."""
        if not is_tool_available("poetry"):
            logger.error(
                "Poetry is not installed. Install it with:\n"
                "  curl -sSL https://install.python-poetry.org | python3 -\n"
                "  or: pipx install poetry"
            )
            raise SystemExit(1)

        pyproject = PROJECT_ROOT / "pyproject.toml"
        if not pyproject.exists():
            content = PYPROJECT_TEMPLATE.format(
                project_name=self.config.project_name,
                python_version=self.config.python_version,
            )
            pyproject.write_text(content)
            logger.info("Created %s", pyproject)
        else:
            logger.info("%s already exists, skipping.", pyproject)

        logger.info(
            "\n"
            "=== Poetry Setup Complete ===\n"
            "\n"
            "Next steps:\n"
            "  1. Edit pyproject.toml to add your dependencies\n"
            "     Or use: poetry add <package>\n"
            "  2. Run: python dependency_manager.py lock\n"
            "  3. Run: python dependency_manager.py sync --env dev\n"
            "\n"
            "IMPORTANT: Commit pyproject.toml AND poetry.lock to version control.\n"
        )

    def lock(self) -> None:
        """Generate / update poetry.lock from pyproject.toml."""
        logger.info("Generating poetry.lock ...")
        run_command(["poetry", "lock", "--no-update"])
        logger.info("poetry.lock generated successfully.")

        lock_path = PROJECT_ROOT / "poetry.lock"
        if lock_path.exists():
            file_hash = compute_file_hash(lock_path)
            logger.info("  poetry.lock hash: %s", file_hash)

    def sync(self, env: str = "dev") -> None:
        """Install dependencies from poetry.lock."""
        logger.info("Syncing environment (%s) ...", env)

        cmd = ["poetry", "install"]
        if env == "prod":
            cmd.extend(["--only", "main", "--no-interaction"])
        elif env == "ci":
            cmd.extend(["--no-interaction", "--no-ansi"])
        else:
            cmd.append("--no-interaction")

        run_command(cmd)
        logger.info("Environment synced successfully.")

    def update(self, package: Optional[str] = None) -> None:
        """Update dependencies."""
        if package:
            logger.info("Updating %s ...", package)
            run_command(["poetry", "update", package])
        else:
            logger.info("Updating all dependencies ...")
            run_command(["poetry", "update"])

        logger.info("Update complete. Review changes with: git diff poetry.lock")

    def parse_lock_file(self, env: str = "prod") -> List[DependencyInfo]:
        """Parse poetry.lock into DependencyInfo objects using `poetry show`."""
        cmd = ["poetry", "show", "--no-interaction", "--no-ansi"]
        if env == "prod":
            cmd.append("--only=main")

        result = run_command(cmd, check=False)
        dependencies = []
        if result.returncode == 0 and result.stdout:
            for line in result.stdout.strip().split("\n"):
                parts = line.split()
                if len(parts) >= 2:
                    dependencies.append(
                        DependencyInfo(name=parts[0], version=parts[1])
                    )
        return dependencies

    def export_requirements(self, output_file: str = "requirements.txt", env: str = "prod") -> None:
        """Export poetry.lock to requirements.txt format with hashes."""
        logger.info("Exporting to %s ...", output_file)
        cmd = [
            "poetry", "export",
            "--format", "requirements.txt",
            "--output", output_file,
            "--no-interaction",
        ]
        if env == "prod":
            cmd.append("--only=main")

        # Poetry export plugin may need to be installed
        try:
            run_command(cmd)
            logger.info("Exported to %s", output_file)
        except SystemExit:
            logger.error(
                "Poetry export failed. You may need to install the export plugin:\n"
                "  poetry self add poetry-plugin-export"
            )
            raise


