class PipBackend:
    """
    Basic pip-based dependency management using pip freeze.

    This is the simplest backend but provides fewer guarantees.
    Recommended only for very simple projects.

    File layout:
        requirements.in      — top-level dependencies (manually maintained)
        requirements.txt     — pip freeze output (pinned versions)
    """

    def __init__(self, config: ProjectConfig):
        self.config = config

    def init(self) -> None:
        """Create initial requirements.in."""
        req_in = PROJECT_ROOT / "requirements.in"
        if not req_in.exists():
            req_in.write_text(REQUIREMENTS_IN_TEMPLATE)
            logger.info("Created %s", req_in)

        logger.info(
            "\n"
            "=== pip Setup Complete ===\n"
            "\n"
            "NOTE: For better dependency management, consider using\n"
            "pip-tools or Poetry instead. Plain pip does not support\n"
            "hash verification or automatic dependency resolution locking.\n"
            "\n"
            "Next steps:\n"
            "  1. Add dependencies to requirements.in\n"
            "  2. Run: pip install -r requirements.in\n"
            "  3. Run: python dependency_manager.py lock\n"
        )

    def lock(self) -> None:
        """Generate requirements.txt from current environment using pip freeze."""
        logger.info("Generating requirements.txt via pip freeze ...")
        result = run_command([sys.executable, "-m", "pip", "freeze"])
        req_txt = PROJECT_ROOT / "requirements.txt"

        header = (
            "# This file is auto-generated by dependency_manager.py\n"
            "# Do not edit manually. Instead, edit requirements.in and re-lock.\n"
            f"# Generated at: {time.strftime('%Y-%m-%d %H:%M:%S UTC', time.gmtime())}\n"
            f"# Python: {sys.version}\n"
            "#\n"
        )
        req_txt.write_text(header + result.stdout)
        logger.info("Created %s", req_txt)
        logger.warning(
            "Note: pip freeze does not include hashes. "
            "Consider switching to pip-tools for hash-verified lock files."
        )

    def sync(self, env: str = "dev") -> None:
        """Install from requirements.txt."""
        req_file = "requirements.txt"
        if not (PROJECT_ROOT / req_file).exists():
            logger.error("requirements.txt not found. Run lock first.")
            raise SystemExit(1)

        cmd = [sys.executable, "-m", "pip", "install", "-r", req_file]
        if env == "ci":
            cmd.append("--no-cache-dir")
        run_command(cmd)
        logger.info("Dependencies installed from %s", req_file)

    def update(self, package: Optional[str] = None) -> None:
        """Update packages and regenerate lock file."""
        if package:
            run_command([sys.executable, "-m", "pip", "install", "--upgrade", package])
        else:
            req_in = PROJECT_ROOT / "requirements.in"
            if req_in.exists():
                run_command([
                    sys.executable, "-m", "pip", "install", "--upgrade", "-r", str(req_in)
                ])
        self.lock()

    def parse_lock_file(self, env: str = "prod") -> List[DependencyInfo]:
        """Parse requirements.txt."""
        filepath = PROJECT_ROOT / "requirements.txt"
        if not filepath.exists():
            return []
        deps = []
        with open(filepath) as f:
            for line in f:
                stripped = line.strip()
                if stripped and not stripped.startswith("#") and "==" in stripped:
                    name, version = stripped.split("==", 1)
                    deps.append(DependencyInfo(name=name.strip(), version=version.strip()))
        return deps


# ---------------------------------------------------------------------------
# Dependency Auditor
# ---------------------------------------------------------------------------

class DependencyAuditor:
    """
    Audits dependencies for known vulnerabilities and best-practice issues.

    Uses:
    - pip-audit (if available) for vulnerability scanning
    - Basic checks for outdated packages, missing hashes, etc.
    """

    def __init__(self, config: ProjectConfig):
        self.config = config

    def audit(self) -> bool:
        """
        Run a full audit. Returns True if no issues found.
        """
        issues_found = False

        logger.info("=" * 60)
        logger.info("DEPENDENCY AUDIT")
        logger.info("=" * 60)

        # 1. Check for known vulnerabilities using pip-audit
        if is_tool_available("pip-audit"):
            logger.info("\n--- Vulnerability Scan (pip-audit) ---")
            result = run_command(
                [sys.executable, "-m", "pip_audit"],
                check=False,
            )
            if result.returncode != 0:
                logger.warning("Vulnerabilities found! See output above.")
                issues_found = True
            else:
                logger.info("No known vulnerabilities found.")
        else:
            logger.warning(
                "pip-audit not installed. Install with: pip install pip-audit\n"
                "Skipping vulnerability scan."
            )

        # 2. Check lock file freshness
        logger.info("\n--- Lock File Freshness ---")
        freshness_ok = self._check_lock_freshness()
        if not freshness_ok:
            issues_found = True

        # 3. Check for hash presence in lock files
        logger.info("\n--- Hash Verification ---")
        hashes_ok = self._check_hashes()
        if not hashes_ok:
            issues_found = True

        # 4. Check for unpinned dependencies in input files
        logger.info("\n--- Pinning Check ---")
        pinning_ok = self._check_pinning()
        if not pinning_ok:
            issues_found = True

        # Summary
        logger.info("\n" + "=" * 60)
        if issues_found:
            logger.warning("AUDIT RESULT: Issues found. Please review above.")
        else:
            logger.info("AUDIT RESULT: All checks passed.")
        logger.info("=" * 60)

        return not issues_found

    def _check_lock_freshness(self) -> bool:
        """Check if lock files are newer than input files."""
        pairs = [
            ("requirements.in", "requirements.txt"),
            ("requirements-dev.in", "requirements-dev.txt"),
        ]

        all_ok = True
        for input_file, lock_file in pairs:
            input_path = PROJECT_ROOT / input_file
            lock_path = PROJECT_ROOT / lock_file

            if not input_path.exists():
                continue

            if not lock_path.exists():
                logger.warning(
                    "  %s exists but %s is missing. Run 'lock' to generate it.",
                    input_file,
                    lock_file,
                )
                all_ok = False
                continue

            input_mtime = input_path.stat().st_mtime
            lock_mtime = lock_path.stat().st_mtime

            if input_mtime > lock_mtime:
                logger.warning(
                    "  %s is newer than %s. Lock file may be stale. "
                    "Run 'lock' to regenerate.",
                    input_file,
                    lock_file,
                )
                all_ok = False
            else:
                logger.info("  %s is up-to-date.", lock_file)

        # Poetry check
        pyproject = PROJECT_ROOT / "pyproject.toml"
        poetry_lock = PROJECT_ROOT / "poetry.lock"
        if pyproject.exists() and poetry_lock.exists():
            if pyproject.stat().st_mtime > poetry_lock.stat().st_mtime:
                logger.warning(
                    "  pyproject.toml is newer than poetry.lock. "
                    "Run 'lock' to regenerate."
                )
                all_ok = False
            else:
                logger.info("  poetry.lock is up-to-date.")

        return all_ok

    def _check_hashes(self) -> bool:
        """Check if lock files contain hashes."""
        all_ok = True
        for filename in ["requirements.txt", "requirements-dev.txt"]:
            filepath = PROJECT_ROOT / filename
            if not filepath.exists():
                continue

            content = filepath.read_text()
            if "--hash=" not in content:
                logger.warning(
                    "  %s does not contain hashes. "
                    "Regenerate with pip-tools to include --generate-hashes.",
                    filename,
                )
                all_ok = False
            else:
                hash_count = content.count("--hash=")
                logger.info("  %s contains %d hashes.", filename, hash_count)

        return all_ok

    def _check_pinning(self) -> bool:
        """Warn about overly broad version specifiers in input files."""
        all_ok = True
        for filename in ["requirements.in", "requirements-dev.in"]:
            filepath = PROJECT_ROOT / filename
            if not filepath.exists():
                continue

            with open(filepath) as f:
                for lineno, line in enumerate(f, 1):
                    stripped = line.strip()
                    if not stripped or stripped.startswith("#") or stripped.startswith("-"):
                        continue

                    # Check for completely unpinned deps (no version specifier)
                    if re.match(r"^[a-zA-Z0-9_.-]+\s*$", stripped):
                        logger.warning(
                            "  %s:%d — '%s' has no version constraint. "
                            "Consider adding a minimum version (e.g., %s>=1.0).",
                            filename,
                            lineno,
                            stripped,
                            stripped,
                        )
                        all_ok = False

        return all_ok


# ---------------------------------------------------------------------------
# Consistency Checker
# ---------------------------------------------------------------------------

class ConsistencyChecker:
    """
    Checks that lock files are consistent across environments and
    that the lock file matches what's actually installed.
    """

    def __init__(self, config: ProjectConfig):
        self.config = config

    def check(self) -> bool:
        """Run all consistency checks."""
        logger.info("=" * 60)
        logger.info("CONSISTENCY CHECK")
        logger.info("=" * 60)

        all_ok = True

        # 1. Check installed packages match lock file
        logger.info("\n--- Installed vs Lock File ---")
        if not self._check_installed_vs_locked():
            all_ok = False

        # 2. Check for duplicate/conflicting dependencies
        logger.info("\n--- Conflict Check ---")
        if not self._check_conflicts():
            all_ok = False

        # 3. Check Python version compatibility
        logger.info("\n--- Python Version ---")
        logger.info(
            "  Current Python: %s.%s.%s",
            sys.version_info.major,
            sys.version_info.minor,
            sys.version_info.micro,
        )

        logger.info("\n" + "=" * 60)
        if all_ok:
            logger.info("CONSISTENCY: All checks passed.")
        else:
            logger.warning("CONSISTENCY: Issues found. See above.")
        logger.info("=" * 60)

        return all_ok

    def _check_installed_vs_locked(self) -> bool:
        """Compare installed packages against the lock file."""
        result = run_command(
            [sys.executable, "-m", "pip", "list", "--format=json"],
            check=False,
        )
        if result.returncode != 0:
            logger.warning("  Could not list installed packages.")
            return False

        installed = {}
        try:
            for pkg in json.loads(result.stdout):
                installed[pkg["name"].lower().replace("-", "_")] = pkg["version"]
        except (json.JSONDecodeError, KeyError):
            logger.warning("  Could not parse pip list output.")
            return False

        # Try to parse the lock file
        lock_file = PROJECT_ROOT / "requirements.txt"
        if not lock_file.exists():
            logger.info("  No requirements.txt to compare against.")
            return True

        locked = {}
        with open(lock_file) as f:
            for line in f:
                stripped = line.strip()
                if stripped and not stripped.startswith("#") and not stripped.startswith("-") and not stripped.startswith("--"):
                    match = re.match(r"^([a-zA-Z0-9_.-]+)==([^\s;\\]+)", stripped)
                    if match:
                        name = match.group(1).lower().replace("-", "_")
                        version = match.group(2)
                        locked[name] = version

        mismatches = []
        missing = []
        for name, version in locked.items():
            if name not in installed:
                missing.append(name)
            elif installed[name] != version:
                mismatches.append((name, version, installed[name]))

        if mismatches:
            logger.warning("  Version mismatches:")
            for name, expected, actual in mismatches:
                logger.warning("    %s: locked=%s, installed=%s", name, expected, actual)

        if missing:
            logger.warning("  Missing packages (locked but not installed):")
            for name in missing:
                logger.warning("    %s", name)

        if not mismatches and not missing:
            logger.info("  All locked packages match installed versions.")
            return True

        return False

    def _check_conflicts(self) -> bool:
        """Check for dependency conflicts using pip check."""
        result = run_command(
            [sys.executable, "-m", "pip", "check"],
            check=False,
        )
        if result.returncode != 0:
            logger.warning("  Dependency conflicts detected:")
            for line in result.stdout.strip().split("\n"):
                logger.warning("    %s", line)
            return False
        else:
            logger.info("  No dependency conflicts found.")
            return True


# ---------------------------------------------------------------------------
# Dependency Tree Viewer
# ---------------------------------------------------------------------------

class DependencyTreeViewer:
    """Displays the dependency tree."""

    @staticmethod
    def show() -> None:
        """Show the dependency tree using pipdeptree if available."""
        if is_tool_available("pipdeptree"):
            result = run_command(["pipdeptree"], check=False)
            if result.returncode == 0:
                print(result.stdout)
                return

        # Fallback: basic listing
        logger.info("pipdeptree not available. Install with: pip install pipdeptree")
        logger.info("Falling back to pip list:")
        result = run_command([sys.executable, "-m", "pip", "list"])
        print(result.stdout)


# ---------------------------------------------------------------------------
# Main CLI
# ---------------------------------------------------------------------------

def get_backend(config: ProjectConfig):
    """Factory to get the appropriate backend."""
    if config.backend == Backend.POETRY:
        return PoetryBackend(config)
    elif config.backend == Backend.PIP_TOOLS:
        return PipToolsBackend(config)
    elif config.backend == Backend.PIP:
        return PipBackend(config)
    else:
        raise ValueError(f"Unknown backend: {config.backend}")


def cmd_init(args: argparse.Namespace) -> None:
    """Initialize the project for dependency management."""
    backend_choice = Backend(args.backend)
    config = ProjectConfig(backend=backend_choice)
    save_config(config)

    backend = get_backend(config)
    backend.init()


def cmd_lock(args: argparse.Namespace) -> None:
    """Generate lock files."""
    config = load_config()
    backend = get_backend(config)
    backend.lock()

    if config.auto_audit:
        logger.info("\nRunning post-lock audit ...")
        auditor = DependencyAuditor(config)
        auditor.audit()


def cmd_sync(args: argparse.Namespace) -> None:
    """Synchronize environment with lock file."""
    config = load_config()
    backend = get_backend(config)
    backend.sync(env=args.env)


def cmd_update(args: argparse.Namespace) -> None:
    """Update dependencies."""
    config = load_config()
    backend = get_backend(config)
    backend.update(package=args.package)


def cmd_audit(args: argparse.Namespace) -> None:
    """Audit dependencies for vulnerabilities and issues."""
    config = load_config()
    auditor = DependencyAuditor(config)
    success = auditor.audit()
    if not success:
        raise SystemExit(1)


def cmd_check_consistency(args: argparse.Namespace) -> None:
    """Check consistency of lock files and installed packages."""
    config = load_config()
    checker = ConsistencyChecker(config)
    success = checker.check()
    if not success:
        raise SystemExit(1)


def cmd_export(args: argparse.Namespace) -> None:
    """Export lock file to a different format."""
    config = load_config()

    if config.backend == Backend.POETRY:
        backend = PoetryBackend(config)
        output = args.output or "requirements.txt"
        backend.export_requirements(output_file=output, env=args.env)
    elif config.backend in (Backend.PIP_TOOLS, Backend.PIP):
        logger.info("Already using requirements.txt format. No export needed.")
        # But we can show the contents
        for filename in ["requirements.txt", "requirements-dev.txt"]:
            filepath = PROJECT_ROOT / filename
            if filepath.exists():
                logger.info("Contents of %s:", filename)
                print(filepath.read_text())
    else:
        logger.error("Export not supported for backend: %s", config.backend.value)


def cmd_show_tree(args: argparse.Namespace) -> None:
    """Show the dependency tree."""
    DependencyTreeViewer.show()


def cmd_info(args: argparse.Namespace) -> None:
    """Show current configuration and status."""
    config = load_config()

    print("\n" + "=" * 60)
    print("DEPENDENCY MANAGER — Project Info")
    print("=" * 60)
    print(f"  Project:          {config.project_name}")
    print(f"  Backend:          {config.backend.value}")
    print(f"  Python version:   {config.python_version}")
    print(f"  Hash algorithm:   {config.hash_algorithm}")
    print(f"  Auto audit:       {config.auto_audit}")
    print(f"  Environments:     {', '.join(config.environments)}")
    print(f"  PyPI index:       {config.pypi_index_url}")

    # Show file status
    print("\n  Files:")
    important_files = [
        "requirements.in",
        "requirements-dev.in",
        "requirements.txt",
        "requirements-dev.txt",
        "pyproject.toml",
        "poetry.lock",
        CONFIG_FILENAME,
    ]
    for filename in important_files:
        filepath = PROJECT_ROOT / filename
        if filepath.exists():
            size = filepath.stat().st_size
            mtime = time.strftime(
                "%Y-%m-%d %H:%M:%S",
                time.localtime(filepath.stat().st_mtime),
            )
            print(f"    ✓ {filename:30s} ({size:>8d} bytes, modified {mtime})")
        else:
            print(f"    ✗ {filename:30s} (not found)")

    # Show venv status
    in_venv = (
        hasattr(sys, "real_prefix")
        or (hasattr(sys, "base_prefix") and sys.base_prefix != sys.prefix)
    )
    print(f"\n  Virtual env:      {'Active' if in_venv else 'NOT ACTIVE (recommended!)'}")
    print(f"  Python path:      {sys.executable}")
    print("=" * 60 + "\n")


def build_parser() -> argparse.ArgumentParser:
    """Build the argument parser."""
    parser = argparse.ArgumentParser(
        prog="dependency_manager",
        description=(
            "Manage Python dependency lock files for consistent, "
            "reproducible environments across dev, CI, and production."
        ),
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  # Initialize with pip-tools (recommended)
  python dependency_manager.py init --backend pip-tools

  # Initialize with Poetry
  python dependency_manager.py init --backend poetry

  # Generate lock files
  python dependency_manager.py lock

  # Install dependencies for development
  python dependency_manager.py sync --env dev

  # Install only production dependencies
  python dependency_manager.py sync --env prod

  # Update a specific package
  python dependency_manager.py update requests

  # Update all packages
  python dependency_manager.py update

  # Audit for vulnerabilities
  python dependency_manager.py audit

  # Check consistency
  python dependency_manager.py check-consistency

  # Show dependency tree
  python dependency_manager.py show-tree

  # Show project info
  python dependency_manager.py info

Best Practices:
  1. ALWAYS commit lock files to version control
  2. Use `lock` to generate, `sync` to install — never `pip install` directly
  3. Run `audit` regularly (and in CI) to catch vulnerabilities
  4. Use separate input files for prod vs dev dependencies
  5. Always work inside a virtual environment
  6. Pin your CI/CD to use `sync --env ci` for reproducible builds
        """,
    )

    subparsers = parser.add_subparsers(dest="command", help="Command to run")

    # init
    init_parser = subparsers.add_parser(
        "init",
        help="Initialize dependency management for this project",
    )
    init_parser.add_argument(
        "--backend",
        choices=["poetry", "pip-tools", "pip"],
        default="pip-tools",
        help="Dependency management backend (default: pip-tools)",
    )
    init_parser.set_defaults(func=cmd_init)

    # lock
    lock_parser = subparsers.add_parser(
        "lock",
        help="Generate/update lock files from dependency specifications",
    )
    lock_parser.set_defaults(func=cmd_lock)

    # sync
    sync_parser = subparsers.add_parser(
        "sync",
        help="Synchronize environment with lock file",
    )
    sync_parser.add_argument(
        "--env",
        choices=["dev", "prod", "ci"],
        default="dev",
        help="Target environment (default: dev)",
    )
    sync_parser.set_defaults(func=cmd_sync)

    # update
    update_parser = subparsers.add_parser(
        "update",
        help="Update one or all dependencies",
    )
    update_parser.add_argument(
        "package",
        nargs="?",
        default=None,
        help="Package to update (omit to update all)",
    )
    update_parser.set_defaults(func=cmd_update)

    # audit
    audit_parser = subparsers.add_parser(
        "audit",
        help="Audit dependencies for vulnerabilities and issues",
    )
    audit_parser.set_defaults(func=cmd_audit)

    # check-consistency
    check_parser = subparsers.add_parser(
        "check-consistency",
        help="Check lock file and environment consistency",
    )
    check_parser.set_defaults(func=cmd_check_consistency)

    # export
    export_parser = subparsers.add_parser(
        "export",
        help="Export lock file to a different format",
    )
    export_parser.add_argument(
        "--output", "-o",
        default=None,
        help="Output file path",
    )
    export_parser.add_argument(
        "--env",
        choices=["dev", "prod"],
        default="prod",
        help="Environment to export (default: prod)",
    )
    export_parser.set_defaults(func=cmd_export)

    # show-tree
    tree_parser = subparsers.add_parser(
        "show-tree",
        help="Display the dependency tree",
    )
    tree_parser.set_defaults(func=cmd_show_tree)

    # info
    info_parser = subparsers.add_parser(
        "info",
        help="Show current configuration and project status",
    )
    info_parser.set_defaults(func=cmd_info)

    return parser


def main() -> None:
    """Entry point."""
    parser = build_parser()
    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        raise SystemExit(0)

    args.func(args)


if __name__ == "__main__":
    main()